    "description": "documentation portal",
    "url": "https://windmill.dev"
  },
  "servers": [
    {
      "url": "/api"
    }
  ],
  "security": [
    {
      "bearerAuth": []
    },
    {
      "cookieAuth": []
    }
  ],
  "paths": {
    "/version": {
      "get": {
        "summary": "get backend version",
        "operationId": "backendVersion",
        "tags": [
          "settings"
        ],
        "responses": {
          "200": {
            "description": "git version of backend",
            "content": {
              "text/plain": {
                "schema": {
                  "type": "string"
                }
              }
            }
          }
        }
      }
    },
    "/health/status": {
      "get": {
        "summary": "health status",
        "description": "Health status endpoint. Returns cached health status (database connectivity, worker count).\nCache TTL is fixed at 5 seconds. Use force=true query parameter to bypass cache.\nNote: This endpoint is intentionally different from Kubernetes probes to avoid confusion.\nFor k8s liveness/readiness probes, use /version endpoint.\n",
        "operationId": "getHealthStatus",
        "tags": [
          "health"
        ],
        "security": [],
        "parameters": [
          {
            "name": "force",
            "in": "query",
            "description": "Force a fresh check, bypassing the cache",
            "required": false,
            "schema": {
              "type": "boolean",
              "default": false
            }
          }
        ],
        "responses": {
          "200": {
            "description": "server is healthy or degraded",
            "content": {
              "application/json": {
                "schema": {
                  "$ref": "#/components/schemas/HealthStatusResponse"
                }
              }
            }
          },
          "503": {
            "description": "server is unhealthy (database unreachable)",
            "content": {
              "application/json": {
                "schema": {
                  "$ref": "#/components/schemas/HealthStatusResponse"
                }
              }
            }
          }
        }

